mapper.select:
SELECT COUNT(1)
FROM HR_EMPLOYEE_RECRUIT T
WHERE T.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
  AND T.ACTIVITY = #{activity, jdbcType=VARCHAR}

    AND CONVERTTOUNSIGN(UPPER(T.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchName, jdbcType=VARCHAR})) || '%'


    AND T.EMPID LIKE '%' || #{searchEmpId, jdbcType=VARCHAR} || '%'

SELECT * FROM ( SELECT ROWNUM AS RN, A.* FROM ( SELECT T.PERSON_ID, T.EMPID, T.LOCAL_NAME, T.ENGLISH_NAME, T.KOREAN_NAME, T.SEXCODE, GET_GLOBAL_NAME(T.SEXCODE, #{lang, jdbcType=VARCHAR}) AS SEX_NAME, T.DOB, T.DEPTNO, D.ORG_NAME_LOCAL AS DEPT_NAME, T.STANDARD_POSITION, T.POST_FAMILY, T.POST_GRADE_NO, T.POSITION_NO, T.EMP_TYPE_CODE, GET_GLOBAL_NAME(T.EMP_TYPE_CODE, #{lang, jdbcType=VARCHAR}) AS EMP_TYPE_NAME, T.JOIN_TYPE, GET_GLOBAL_NAME(T.JOIN_TYPE, #{lang, jdbcType=VARCHAR}) AS JOIN_TYPE_NAME, T.DATE_STARTED, T.ACTIVITY, TO_CHAR(T.CREATE_DATE, 'YYYY/MM/DD') AS CREATE_DATE, T.CREATED_BY, TO_CHAR(T.UPDATE_DATE, 'YYYY/MM/DD HH24:MI') AS UPDATE_DATE, T.UPDATED_BY FROM HR_EMPLOYEE_RECRUIT T LEFT JOIN HR_ORGANIZATION D ON D.ORG_CODE = T.DEPTNO AND D.CPNY_ID = T.CPNY_ID AND D.ACTIVITY = '1' WHERE T.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND T.ACTIVITY = #{activity, jdbcType=VARCHAR}
AND CONVERTTOUNSIGN(UPPER(T.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchName, jdbcType=VARCHAR})) || '%'
AND T.EMPID LIKE '%' || #{searchEmpId, jdbcType=VARCHAR} || '%'
ORDER BY T.CREATE_DATE DESC ) A WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC} ) WHERE RN > #{start, jdbcType=NUMERIC}

mapper.update:
